using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(app.Environment.ContentRootPath, "Data", "ChurnModel.zip");
var svc = new ChurnModelService(dataPath, modelPath);

app.MapPost("/train", () =>
{
    var result = svc.Train();
    return Results.Ok(new { message = "Model trained", metrics = result });
});

app.MapPost("/predict", (CustomerData customer) =>
{
    var prediction = svc.Predict(customer);
    return Results.Ok(new
    {
        willChurn = prediction.PredictedChurned,
        probability = prediction.Probability
    });
});

app.Run();

