{"file_text": "using Microsoft.ML;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public class ChurnModelService
{
    private readonly MLContext _mlContext = new(seed: 0);
    private ITransformer? _model;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ChurnModelService(string dataPath, string modelPath)
    {
        _dataPath = dataPath;
        _modelPath = modelPath;
    }

    public string Train()
    {
        var data = _mlContext.Data.LoadFromTextFile<CustomerData>(
            _dataPath, hasHeader: true, separatorChar: ',');

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

        var pipeline = _mlContext.Transforms.Categorical
                .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
            .Append(_mlContext.Transforms.Concatenate("Features",
                nameof(CustomerData.Age),
                nameof(CustomerData.Income),
                "RegionEncoded",
                nameof(CustomerData.PurchaseHistory)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.BinaryClassification.Trainers
                .SdcaLogisticRegression(labelColumnName: "Label", featureColumnName: "Features"));

        _model = pipeline.Fit(split.TrainSet);

        var predictions = _model.Transform(split.TestSet);
        var metrics = _mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

        _mlContext.Model.Save(_model, data.Schema, _modelPath);

        return $"Accuracy: {metrics.Accuracy:P2} | AUC: {metrics.AreaUnderRocCurve:P2} | F1: {metrics.F1Score:P2}";
    }

    public ChurnPrediction Predict(CustomerData customer)
    {
        EnsureModelLoaded();
        var engine = _mlContext.Model
            .CreatePredictionEngine<CustomerData, ChurnPrediction>(_model!);
        return engine.Predict(customer);
    }

    private void EnsureModelLoaded()
    {
        if (_model is not null) return;

        if (!File.Exists(_modelPath))
            throw new InvalidOperationException(
                "Model not found. Call POST /train first.");

        _model = _mlContext.Model.Load(_modelPath, out _);
    }
}
